const text = await space.api.fileRead(path, "utf8");
const data = space.utils.yaml.parse(text);

function updateInObject(obj) {
  if (Array.isArray(obj)) {
    for (const item of obj) updateInObject(item);
    return;
  }
  if (obj && typeof obj === "object") {
    for (const [k, v] of Object.entries(obj)) {
      if (k === "mr_kowalski") obj[k] = "John Ronald Kowalski";
      else updateInObject(v);
    }
  }
}

updateInObject(data);

